// Webhook input structure:
// items = [ { json: { headers, params, query, body: [ {row1}, {row2}, ... ] } } ]
// Output: 1 item / học sinh với: student_id, name, class, C1..C13, total_raw, total_10

function pickKey(obj, containsText) {
  return Object.keys(obj).find(k => k.includes(containsText));
}

const root = items?.[0]?.json ?? {};
const rows = Array.isArray(root.body) ? root.body : [];  // <-- 20 học sinh nằm ở đây

const outputItems = rows.map((r) => {
  const out = {};

  // basic fields
  out.student_id = r["Mã HS"] ?? r["Ma HS"] ?? r["ID"] ?? r["Student ID"] ?? null;
  out.name = r["Họ và tên"] ?? r["Ho va ten"] ?? r["Name"] ?? null;
  out.class = r["Lớp"] ?? r["Lop"] ?? r["Class"] ?? null;

  // map Câu 1..13 (key dài -> tìm bằng "Câu i")
  let sum = 0;
  for (let i = 1; i <= 13; i++) {
    const k =
      pickKey(r, Câu ${i}\n) ||
      pickKey(r, Câu ${i}) ||
      pickKey(r, Cau ${i}); // phòng trường hợp mất dấu

    const val = k ? Number(r[k]) : 0;
    out[`C${i}`] = Number.isFinite(val) ? val : 0;
    sum += out[`C${i}`];
  }

  // totals
  const totalKey = pickKey(r, "Tổng điểm thô") || pickKey(r, "Tong diem tho");
  const totalRaw = totalKey != null ? Number(r[totalKey]) : sum;
  out.total_raw = Number.isFinite(totalRaw) ? totalRaw : sum;

  const total10Key = pickKey(r, "Điểm quy đổi thang 10") || pickKey(r, "Diem quy doi thang 10");
  const total10 = total10Key != null ? Number(r[total10Key]) : null;
  out.total_10 = Number.isFinite(total10) ? total10 : null;

  return { json: out };
});

return outputItems;

// Input: items = danh sách học sinh đã có C1..C13
// Output: 13 dòng, mỗi dòng là 1 "chuẩn" với Fail/Pass/Excellent

const standardMap = [
  { c: "C1",  code: "3Np.05" },
  { c: "C2",  code: "3Np.01" },
  { c: "C3",  code: "3Np.04" },
  { c: "C4",  code: "3Np.03" },
  { c: "C5",  code: "3Nm.02" },
  { c: "C6",  code: "3Nc.05" },
  { c: "C7",  code: "3Ni.07" },
  { c: "C8",  code: "3Ni.06" },
  { c: "C9",  code: "3Ni.10" },
  { c: "C10", code: "TWM.01-02" },
  { c: "C11", code: "TWM.03-04" },
  { c: "C12", code: "TWM.05-06" },
  { c: "C13", code: "TWM.07-08" },
];

const students = items.map(i => i.json);
const n = students.length;

function bucket(score) {
  // Fail: 0-1; Pass: 2-3; Excellent: 4
  if (score <= 1) return "fail";
  if (score <= 3) return "pass";
  return "excellent";
}

const result = standardMap.map(({c, code}) => {
  let fail = 0, pass = 0, excellent = 0;

  for (const s of students) {
    const sc = Number(s[c] ?? 0);
    const b = bucket(sc);
    if (b === "fail") fail++;
    else if (b === "pass") pass++;
    else excellent++;
  }

  const failRate = n ? fail / n : 0;
  const passRate = n ? pass / n : 0;
  const excellentRate = n ? excellent / n : 0;

  return {
    standard_code: code,
    câu_hỏi: c,
    số_học_sinh: n,
    số_học_sinh_rớt: fail,
    số_học_sinh_đạt: pass,
    số_học_sinh_đạt_điểm_4: excellent,
    tỉ_lệ_fail: Math.round(failRate * 1000) / 10,        // %
    tỉ_lệ_pass: Math.round(passRate * 1000) / 10,        // %
    tỉ_lệ_excellent: Math.round(excellentRate * 1000) / 10, // %
  };
});

// mỗi item 1 chuẩn để dễ đưa ra sheet/dashboard
return result.map(r => ({ json: r }));

// Input: 13 items từ bước trước (mỗi item 1 chuẩn)

const standards = items.map(i => i.json);

function num(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

const updated = standards.map(s => {
  // support 2 naming styles
  const fail = num(s.fail_rate ?? s["tỉ_lệ_fail"] ?? s["ti_le_fail"] ?? s["ti_le_fail_rate"]);
  const pass = num(s.pass_rate ?? s["tỉ_lệ_pass"] ?? s["ti_le_pass"] ?? s["ti_le_pass_rate"]);

  const improvement_rate = fail + pass;

  return {
    ...s,
    tỉ_lệ_cần_cải_thiện: Math.round(improvement_rate * 10) / 10
  };
});

// Sort giảm dần theo improvement_rate
updated.sort((a, b) => num(b.improvement_rate) - num(a.improvement_rate));

return updated.map(r => ({ json: r }));

function cleanJsonString(s) {
  if (!s) return null;

  // bỏ ```json ... ```
  s = s.replace(/```json/gi, '').replace(/```/g, '').trim();

  // Nếu có dấu nháy bao quanh toàn bộ (do escape)
  // cố parse trực tiếp trước
  try {
    return JSON.parse(s);
  } catch (e) {
    // fallback: đôi khi chuỗi đã là JSON string escaped kiểu "{\n \"a\": 1}"
    try {
      const unescaped = JSON.parse("${s.replace(/"/g, '\\"')}");
      return JSON.parse(unescaped);
    } catch (e2) {
      return null;
    }
  }
}

return items.map(item => {
  const raw = item.json.output; // field output của AI Agent
  const parsed = cleanJsonString(raw);

  if (!parsed) {
    return {
      json: {
        ...item.json,
        parse_error: true,
        raw_output: raw,
      }
    };
  }

  return {
    json: {
      ...item.json,
      ...parsed,
      parse_error: false,
    }
  };
});

