// n8n Code node (Run Once for All Items)

// 1) Lấy body từ Webhook
const body = items?.[0]?.json?.body;

// Nếu webhook gửi thẳng object thay vì array
const rows = Array.isArray(body) ? body : (body ? [body] : []);

// 2) Helpers
const isQuestionKey = (k) => typeof k === 'string' && k.trim().startsWith('Câu ');
const toNumber = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
};

// Parse mã chuẩn từ text key của câu hỏi, ví dụ:
// "Câu 1...\nChuẩn:\n3Np.05 ..." hoặc "Chuẩn: TWM.01-02 ..."
const extractStandardCode = (questionKey) => {
  if (typeof questionKey !== 'string') return '';
  // ưu tiên bắt sau "Chuẩn:" hoặc "Chuẩn:\n"
  const m = questionKey.match(/Chuẩn:\s*([\w.\-]+(?:\s*-\s*[\w.\-]+)?)/i);
  if (!m) return '';
  return m[1].replace(/\s+/g, '').replace(/–/g, '-');
};

// Classify theo điểm 0-4
const classify = (score) => {
  if (score >= 4) return 'excellent';
  if (score >= 2) return 'pass';
  return 'fail'; // 0-1
};

// Risk theo % tổng điểm / 52
const riskLevel = (percent) => {
  if (percent >= 70) return 'Low';
  if (percent >= 40) return 'Medium';
  return 'High';
};

// 3) Transform mỗi học sinh -> output sheet2
const out = rows.map((r) => {
  // lấy các cột câu hỏi
  const qKeys = Object.keys(r).filter(isQuestionKey);

  let total = 0;
  let excellent = 0, pass = 0, fail = 0;

  const strong = [];
  const weak = [];
  const reinforce = [];

  for (const k of qKeys) {
    const score = toNumber(r[k]);
    total += score;

    const type = classify(score);
    if (type === 'excellent') excellent++;
    else if (type === 'pass') pass++;
    else fail++;

    const std = extractStandardCode(k);
    if (!std) continue;

    if (type === 'excellent') strong.push(std);
    else if (type === 'fail') weak.push(std);
    else reinforce.push(std); // pass (2-3)
  }

  // max 52 (13 câu * 4)
  const percent = (total / 52) * 100;
  const diem10 = Math.round((total / 52) * 10 * 10) / 10; // 1 chữ số thập phân

  // unique + join
  const uniqJoin = (arr) => [...new Set(arr)].join(', ');

  return {
    // giữ field tiếng Việt
    "Mã HS": r["Mã HS"] ?? r["Mã_HS"] ?? r["ma_hs"] ?? r["id"] ?? null,
    "Họ và tên": r["Họ và tên"] ?? r["Họ_tên"] ?? r["ho_ten"] ?? '',
    "Lớp": r["Lớp"] ?? r["lop"] ?? '',

    "Tổng điểm": total,
    "Điểm thang 10": diem10,

    "Số Excellent": excellent,
    "Số câu Pass": pass,
    "Số câu Fail": fail,
    "Câu hỏi đạt điểm tốt": uniqJoin(strong),
    "Câu hỏi còn yếu": uniqJoin(weak),
    "Câu hỏi cần củng cố": uniqJoin(reinforce),

    "Risk Level": riskLevel(percent),

    // để trống, bước AI sau mới fill
    "Đánh giá học sinh": "",
  };
});

// 4) Trả về 1 item / 1 học sinh (để ghi sheet dễ)
return out.map((x) => ({ json: x }));

