// n8n Code node (Run Once for All Items)
// Input: items[0].json.body = array students

const payload = items[0].json;
const students = Array.isArray(payload.body) ? payload.body : [];

// Lấy mã chuẩn từ key cột câu hỏi (vd: 3Np.05, TWM.07-08)
function extractStandardCode(colName) {
  const m = colName.match(/\b\d+[A-Za-z]{1,3}\.\d{2}\b|\bTWM\.\d{2}-\d{2}\b/);
  return m ? m[0] : null;
}

// Risk theo % đạt trên tổng 52: >=70 Low, 40-69 Medium, <40 High
function calcRisk(total, max = 52) {
  const percent = max > 0 ? (total / max) * 100 : 0;
  if (percent >= 70) return "Low";
  if (percent >= 40) return "Medium";
  return "High";
}

const out = [];

for (const s of students) {
  const maHS = s["Mã HS"];
  const totalRaw = Number(s["Tổng điểm thô\n(Max: 52)"] ?? 0);
  const diem10 = Number(s["Điểm quy đổi thang 10"] ?? 0);

  const questionKeys = Object.keys(s).filter(k => k.startsWith("Câu "));

  let failCount = 0;
  const weakStandards = [];

  for (const k of questionKeys) {
    const score = Number(s[k] ?? 0);
    const code = extractStandardCode(k);
    if (!code) continue;

    // Fail = 0-1 điểm
    if (score <= 1) {
      failCount += 1;
      weakStandards.push(code);
    }
  }

  // Filter condition (workflow #3)
  const isIntervention = (diem10 < 5) || (failCount >= 4);
  if (!isIntervention) continue;

  out.push({
    "Mã HS": maHS,
    "Tổng điểm": totalRaw,
    "Số chuẩn Fail": failCount,
    "Chuẩn yếu": weakStandards.join(", "),
    "Risk Level": calcRisk(totalRaw, 52),
    "Gợi ý can thiệp": ""
  });
}

// Output: mỗi HS cần can thiệp = 1 item
return out.map(x => ({ json: x }));

