function safeJsonParse(s) {
  try { return JSON.parse(s); } catch { return null; }
}

return $input.all().map((item) => {
  const j = item.json;
  const raw = j.output;

  let parsed = typeof raw === "string" ? safeJsonParse(raw) : null;
  if (!parsed && raw && typeof raw === "object") parsed = raw;

  const suggestion =
    (parsed && (parsed["Gợi ý can thiệp"] || parsed["Goi y can thiep"])) ??
    (typeof raw === "string" ? raw : "");

  return {
    json: {
      ...j,
      "Gợi ý can thiệp": suggestion,
    },
  };
});

function safeJsonParse(s) {
  try { return JSON.parse(s); } catch { return null; }
}

function cleanText(s) {
  if (s == null) return "";
  let t = String(s);

  const parsed = safeJsonParse(t);
  if (parsed && typeof parsed === "object") {
    t = parsed["Gợi ý can thiệp"] ?? parsed["Goi y can thiep"] ?? t;
  }

  t = t
    .replace(/\\n/g, "\n")
    .replace(/\\"/g, '"')
    .trim();

  t = t.replace(/\n{3,}/g, "\n\n");
  return t;
}

function pickIntervention(j) {
  if (j["Gợi ý can thiệp"]) return j["Gợi ý can thiệp"];

  if (typeof j.output === "string") {
    const parsed = safeJsonParse(j.output);
    if (parsed && typeof parsed === "object") {
      return parsed["Gợi ý can thiệp"] ?? parsed["Goi y can thiep"] ?? j.output;
    }
    return j.output;
  }

  return "";
}

const data = $input.all().map(i => i.json);

const rows = data.map(j => ({
  "Mã HS": j["Mã HS"],
  "Tổng điểm": j["Tổng điểm"],
  "Số chuẩn Fail": j["Số chuẩn Fail"],
  "Chuẩn yếu": j["Chuẩn yếu"],
  "Risk Level": j["Risk Level"],
  "Gợi ý can thiệp": cleanText(pickIntervention(j)),
}));

return [{
  json: {
    Sheets: 3,
    data: rows
  }
}];

